  "use client";
  
  import styles from "./styles.module.scss";
  import Image from "next/image";
  import Link from "next/link";
  import HomeHeader from "@/components/HomeHeader/index";
  import HomeFooter from "@/components/HomeFooter/index";
  import { useEffect, useRef, useState } from "react";
  
  export default function TinTuc() {
    const newsContainerRef = useRef<HTMLDivElement>(null);
    const [selectedDate, setSelectedDate] = useState<string | null>(null);
    const [filteredNews, setFilteredNews] = useState<NewsItem[]>([]);
  
    useEffect(() => {
      const observer = new IntersectionObserver(
        (entries) => {
          entries.forEach((entry) => {
            if (entry.isIntersecting) {
              entry.target.classList.add(styles.show);
            } else {
              entry.target.classList.remove(styles.show);
            }
          });
        },
        {
          threshold: 0.1,
        }
      );
  
      if (newsContainerRef.current) {
        const newsItems: NodeListOf<Element> =
          newsContainerRef.current.querySelectorAll(`.${styles.newsItem}`);
  
        newsItems.forEach((item: Element) => observer.observe(item));
  
        return () => {
          newsItems.forEach((item: Element) => observer.unobserve(item));
        };
      }
  
      return () => {};
    }, []);
  
    const handleDateChange = (event: React.ChangeEvent<HTMLInputElement>) => {
      const date = event.target.value;
      setSelectedDate(date);
    };
  
    useEffect(() => {
      if (selectedDate) {
        const filtered = newsData.filter((news) => news.date === selectedDate);
        setFilteredNews(filtered);
      } else {
        setFilteredNews(newsData);
      }
    }, [selectedDate]);
  
    return (
      <>
        <HomeHeader />
  
        <section className={styles.newsSection}>
          <h2 className={styles.sectionTitle}>Tin Tức Nổi Bật</h2>
  
          <div className={styles.dateFilter}>
            <label htmlFor="newsDate">Chọn ngày:</label>
            <input
              type="date"
              id="newsDate"
              onChange={handleDateChange}
              value={selectedDate || ""}
            />
            <button onClick={() => setSelectedDate(null)}>Xóa bộ lọc</button>
          </div>
  
          <div className={styles.newsContainer} ref={newsContainerRef}>
            {(filteredNews.length > 0 ? filteredNews : newsData).map((news) => (
              <div
                key={news.id}
                className={`${styles.newsItem} ${styles.slideIn}`}
              >
                <div className={styles.newsImage}>
                  <Image
                    src={news.image}
                    alt={news.title}
                    width={500}
                    height={300}
                    layout="responsive"
                    objectFit="cover"
                  />
                </div>
                <div className={styles.newsContent}>
                  <h3>{news.title}</h3>
                  <p>{news.content}</p>
                  <Link href={news.link} className={styles.readMore}>
                    Đọc thêm
                  </Link>
                  <p className={styles.newsDate}>Ngày: {news.date}</p>
                </div>
              </div>
            ))}
          </div>
        </section>
  
        <HomeFooter />
      </>
    );
  }